#!/usr/bin/env bash
# eval-driven-mvp.sh — Eval-driven 迭代循环（MVP → 生产的主循环） SOP walkthrough for AI 产品经理 (LLM 应用 / 生成式 AI / Agent 产品 / Copilot 嵌入 — 跨模型评估 / 工作流设计 / 产品-工程协同).
# Auto-generated by cli_writer.py. Source: research/03-workflows.md.
set -euo pipefail
SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
source "${SCRIPT_DIR}/../lib/common.sh"

INDUSTRY="AI 产品经理 (LLM 应用 / 生成式 AI / Agent 产品 / Copilot 嵌入 — 跨模型评估 / 工作流设计 / 产品-工程协同)"
WORKFLOW="Eval-driven 迭代循环（MVP → 生产的主循环）"

usage() {
  cat <<EOF
eval-driven-mvp.sh — Walk through "${WORKFLOW}" SOP for ${INDUSTRY}

逐步走完这个工作流的入门 SOP, 然后做失败模式自检, 输出走查报告。

USAGE:
  ./eval-driven-mvp.sh             # interactive
  ./eval-driven-mvp.sh --dry-run
  ./eval-driven-mvp.sh --json
  ./eval-driven-mvp.sh --explain
  ./eval-driven-mvp.sh --help
EOF
}

explain() {
  cat <<'EOT'
这个 SOP 走查脚本帮你完成 "Eval-driven 迭代循环（MVP → 生产的主循环）" 工作流。

一句话: eval 体系建好后，每一轮迭代用「error analysis → 假设 → 改 → 重新 eval」的闭环把产品质量系统性往上推 —— 从「质量上不去、不知道动哪」状态到「每轮都有可度量提升」状态。这是 AI 产品 ship 之后的日常主循环。

入门 SOP 共 5 步, 失败模式自检 4 项。

相关心智模型:
  • Eval 是地基,不是可选项（别 vibe-check）: 「AI 产品的『好』不是看几个 case 觉得行就 ship —— 是先针对你**自己产品的失败模式**建一套可重复、可回归的系统化测量;没有 eval 就是在瞎改。」
  • 先 error analysis,再加功能（PM 亲自看 trace）: 「质量上不去时,资深 AI PM 的第一反应**不是加功能**,是 PM 亲自拉 10-50 个真实 trace（trace 条数量级见 Hamel field-guide T03-S001 / ev

来源: research/03-workflows.md.
EOT
}

DRY_RUN=0; JSON=0
for arg in "$@"; do
  case "$arg" in
    --help|-h) usage; exit 0 ;;
    --explain) explain; exit 0 ;;
    --dry-run) DRY_RUN=1 ;;
    --json) JSON=1 ;;
  esac
done

declare -a SOP_STEPS=(
  "**Analyze（看数据找 failure mode）**：定期采样 production trace，PM 亲自读，定性识别这一轮最痛的 failure mode。PM 主导。跳过 → 凭直觉猜要改什么，大概率改错地方。 (evidence: [T03-S001, T03-S006])"
  "**频率排序定优先级**：用「这个 failure mode 出现多少次」而不是「我觉得这个重要」来排。PM 主导。跳过 → 花一周修一个一年出现两次的边角问题。 (evidence: [T03-S001, T03-S007])"
  "**对 top failure mode 做根因分析 + 提假设**：drill 进具体失败 pattern（Hamel 案例：日期处理 66% 失败），形成「改 X 应该能修好」的可验证假设。PM + 工程师 + 领域专家。跳过 → 不知道为什么错就乱改架构。 (evidence: [T03-S001])"
  "**Measure（针对性改 + 量化验证）**：按假设做最小改动——规格不清就改 prompt / context，泛化不行才动架构，**fine-tune 放最后**。在窄而具体的 binary 指标上量化前后（Hamel 案例：日期 33%→95%）。PM 主导改 prompt，工程师做架构/scorer。跳过 → 改完不知道有没有用，回到 vibes。 (evidence: [T03-S001, T03-S006])"
  "**Improve → 回归 → 循环回 Analyze**：跑全套 eval 确认没弄坏别的，把这次的 production 失败样本加进 golden set，回到 step 1。PM + 工程师。跳过 → 修 A 弄坏 B，eval 套件不增长就慢慢失效。 (evidence: [T03-S006, T03-S012])"
)
declare -a FAILURE_MODES=(
  "**瓶颈时加功能而不做 error analysis**：触发原因 = 加功能有「在推进」的感觉，error analysis 像在原地;怎么避免 = 把 error analysis 设成迭代的强制 step 1。（**CLI 自检项**：Is your response to \"quality isn't improving\" to add a feature? Stop — pull 50-100 failure samples and categorize first.） (evidence: [T03-S001])"
  "**用 1-5 分而非 binary**：触发原因 = 觉得分数更「细腻」;怎么避免 = 改成 pass/fail，专家二元判断更可靠、更可回归。（**CLI 自检项**：Are your evals scored 1-5? Switch to binary pass/fail — Likert scores are noisy and hard to act on.） (evidence: [T03-S016])"
  "**eval 套件不随 production 失败增长**：触发原因 = 建完 golden set 就不管了;怎么避免 = 每轮把新发现的 production 失败加进 golden set。（**CLI 自检项**：Has your golden set grown with newly discovered production failures? A static eval suite slowly stops catching real regressions.） (evidence: [T03-S012])"
  "**判断「过早自动化」失去信任**：触发原因 = 想省人工;怎么避免 = 早期保持高人工参与，定期 recalibrate judge。（**CLI 自检项**：Did you fully automate evaluation early and now distrust the numbers? Re-introduce human review and recalibrate the judge.） (evidence: [T03-S001])"
)
declare -a STEP_STATUS=()
declare -a STEP_NOTES=()
declare -a FAIL_CHECK=()

ms_section "${INDUSTRY} · ${WORKFLOW} 走查"
ms_info "逐步走完 ${#SOP_STEPS[@]} 步入门 SOP。每步可标 done / skipped / blocked。"
echo

for i in "${!SOP_STEPS[@]}"; do
  ms_section "Step $((i+1))/${#SOP_STEPS[@]}: ${SOP_STEPS[$i]}"
  ms_prompt "状态? [d=done / s=skipped / b=blocked]"
  read -r status
  STEP_STATUS+=("${status:-d}")
  case "${status:-d}" in
    s) ms_prompt "跳过原因 (一句话):"; read -r note ;;
    b) ms_prompt "blocker (一句话):"; read -r note ;;
    *) note="" ;;
  esac
  STEP_NOTES+=("$note")
done

if [[ ${#FAILURE_MODES[@]} -gt 0 ]]; then
  ms_section "失败模式自检"
  for fm in "${FAILURE_MODES[@]}"; do
    if ms_confirm "你是否避免了 — '$fm' ?"; then
      FAIL_CHECK+=("✓ $fm")
    else
      FAIL_CHECK+=("✗ $fm")
    fi
  done
fi

ms_buffer_append "# ${INDUSTRY} — ${WORKFLOW} 走查报告"
ms_buffer_append ""
ms_buffer_append "_生成时间: $(date '+%Y-%m-%d %H:%M:%S')_"
ms_buffer_append ""
ms_buffer_append "## SOP 步骤"
ms_buffer_append ""
for i in "${!SOP_STEPS[@]}"; do
  status_icon="?"
  case "${STEP_STATUS[$i]}" in
    d|D) status_icon="✓" ;;
    s|S) status_icon="↷" ;;
    b|B) status_icon="✗" ;;
  esac
  if [[ -n "${STEP_NOTES[$i]}" ]]; then
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]} — ${STEP_NOTES[$i]}"
  else
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]}"
  fi
done
ms_buffer_append ""
if [[ ${#FAIL_CHECK[@]} -gt 0 ]]; then
  ms_buffer_append "## 失败模式自检"
  ms_buffer_append ""
  for line in "${FAIL_CHECK[@]}"; do
    ms_buffer_append "- $line"
  done
  ms_buffer_append ""
fi

if [[ $JSON -eq 1 ]]; then
  ms_emit_json \
    "workflow" "${WORKFLOW}" \
    "step_count" "${#SOP_STEPS[@]}" \
    "failure_check_count" "${#FAILURE_MODES[@]}"
elif [[ $DRY_RUN -eq 1 ]]; then
  ms_emit_md_stdout
else
  ms_emit_md_file "eval-driven-mvp-walkthrough"
fi
